mapper.update:
UPDATE esg.tb_orgn_status
   SET write_dt = #{writeDt},	
   	   orgn_id = #{orgnId},	
       use_yn = #{useYn},		   
	   updated_at = now(),
	   updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}

UPDATE esg.tb_orgn_status_detail
   SET gubun = #{gubun},
	   work_desc = #{workDesc},
	   issue = #{issue},
	   risk = #{risk},
	   chance = #{chance},
	   use_yn = #{useYn},
	   updated_at = now(),
	   updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}
   AND doc_seq = #{docSeq}

UPDATE esg.tb_approval_info
   SET hr_Id = #{hrId}
     , signature = #{signature}
 WHERE target_type = #{targetType}
   AND target_id = #{targetId}
   AND param = #{param}

UPDATE tb_comp_info
SET
use_yn = 'N',
updated_at = now(),
updated_by = #{updatedBy}
WHERE comp_id = #{compId}

UPDATE esg.tb_orgn_status
   SET use_yn = 'N'
     , updated_at = now()
     , updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo};

UPDATE esg.tb_orgn_status_detail
   SET use_yn = 'N'
     , updated_at = now()
     , updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}
   AND doc_seq = #{docSeq}

