SELECT
created_at, created_by, updated_at, updated_by, 'U' cmd FROM tb_orgn_status
WHERE status_cd = #{statusCd}

select t1.write_year
	, t1.doc_type
	, t1.doc_no
	, t1.comp_id
from esg.tb_orgn_status t1
where t1.write_year = #{writeYear}
	and t1.comp_id  = #{compId}
	and t1.use_yn = 'Y'
	and t1.orgn_id = #{searchText}
